import React, { useState } from 'react';
import { Save, Trophy, Scale, Ruler, Calendar, Star, Lock, Unlock, Flame, TrendingUp } from 'lucide-react';

const Profile = ({ user, setUser }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [formData, setFormData] = useState({
    username: user?.username || 'User',
    email: user?.email || 'user@example.com',
    height: user?.height || 170,
    weight: user?.weight || 70,
    age: user?.age || 25,
    gender: user?.gender || 'Male',
    weeklyGoal: user?.weeklyGoal || 4
  });

  const heightInM = formData.height / 100;
  const bmi = formData.weight && heightInM ? parseFloat((formData.weight / (heightInM * heightInM)).toFixed(1)) : 0;
  
  const getBMICategory = (bmi) => {
    if (bmi < 18.5) return { label: 'Underweight', color: '#f59e0b' };
    if (bmi < 24.9) return { label: 'Normal', color: '#10b981' };
    if (bmi < 29.9) return { label: 'Overweight', color: '#f59e0b' };
    return { label: 'Obese', color: '#ef4444' };
  };

  const bmiCategory = getBMICategory(bmi);

  const handleSave = () => {
    if (setUser) setUser({ ...user, ...formData });
    setIsEditing(false);
  };

  const allBadges = [
    { name: 'First Workout', icon: '🎯', description: 'Complete your first workout', earned: user?.badges?.includes('First Workout') },
    { name: '7 Day Streak', icon: '🔥', description: 'Work out 7 days in a row', earned: user?.badges?.includes('7 Day Streak') },
    { name: '30 Day Streak', icon: '💪', description: 'Work out 30 days in a row', earned: user?.badges?.includes('30 Day Streak') },
    { name: '50 Club', icon: '🏆', description: 'Complete 50 workouts', earned: user?.badges?.includes('50 Club') },
    { name: 'Calorie Crusher', icon: '⚡', description: 'Burn 10,000 calories', earned: user?.badges?.includes('Calorie Crusher') },
    { name: 'Early Bird', icon: '🌅', description: 'Complete workout before 7AM', earned: user?.badges?.includes('Early Bird') },
  ];

  return (
    <div className="profile-page">
      <h1 className="page-title">Profile</h1>

      <div className="profile-grid">
        {/* Profile Card */}
        <div className="profile-card">
          <div className="profile-header">
            <div className="profile-avatar">
              {formData.username?.charAt(0)?.toUpperCase() || 'U'}
            </div>
            <div className="profile-info">
              <h3>{formData.username}</h3>
              <p>{formData.email}</p>
            </div>
            <button 
              className={`btn-edit ${isEditing ? 'saving' : ''}`} 
              onClick={() => isEditing ? handleSave() : setIsEditing(true)}
            >
              {isEditing ? <><Save size={16} /> Save</> : <><Unlock size={16} /> Edit</>}
            </button>
          </div>

          <div className="stats-grid-small">
            <div className="stat-box">
              <Scale size={18} />
              <div>
                <label>Weight</label>
                {isEditing ? (
                  <input
                    type="number"
                    value={formData.weight}
                    onChange={(e) => setFormData({...formData, weight: parseFloat(e.target.value)})}
                  />
                ) : (
                  <span>{formData.weight} kg</span>
                )}
              </div>
            </div>
            <div className="stat-box">
              <Ruler size={18} />
              <div>
                <label>Height</label>
                {isEditing ? (
                  <input
                    type="number"
                    value={formData.height}
                    onChange={(e) => setFormData({...formData, height: parseFloat(e.target.value)})}
                  />
                ) : (
                  <span>{formData.height} cm</span>
                )}
              </div>
            </div>
            <div className="stat-box">
              <Calendar size={18} />
              <div>
                <label>Age</label>
                {isEditing ? (
                  <input
                    type="number"
                    value={formData.age}
                    onChange={(e) => setFormData({...formData, age: parseInt(e.target.value)})}
                  />
                ) : (
                  <span>{formData.age} yrs</span>
                )}
              </div>
            </div>
            <div className="stat-box">
              <Star size={18} />
              <div>
                <label>Weekly Goal</label>
                {isEditing ? (
                  <input
                    type="number"
                    value={formData.weeklyGoal}
                    onChange={(e) => setFormData({...formData, weeklyGoal: parseInt(e.target.value)})}
                  />
                ) : (
                  <span>{formData.weeklyGoal} workouts</span>
                )}
              </div>
            </div>
          </div>

          <div className="bmi-section">
            <h3><Scale size={18} />BMI Calculator</h3>
            <div className="bmi-display">
              <div className="bmi-result" style={{ background: `${bmiCategory.color}20`, borderColor: bmiCategory.color }}>
                <span className="bmi-value" style={{ color: bmiCategory.color }}>{bmi}</span>
                <span className="bmi-label" style={{ color: bmiCategory.color }}>{bmiCategory.label}</span>
              </div>
            </div>
          </div>
        </div>

        {/* Achievements Card */}
        <div className="profile-card">
          <h3><Trophy size={20} />Achievements</h3>
          
          <div className="user-stats">
            <div className="stat-card-small">
              <span className="stat-num">{user?.totalWorkouts || 0}</span>
              <span className="stat-label">Total Workouts</span>
            </div>
            <div className="stat-card-small">
              <span className="stat-num">{user?.currentStreak || 0}</span>
              <span className="stat-label">Current Streak</span>
            </div>
            <div className="stat-card-small">
              <span className="stat-num">{user?.longestStreak || 0}</span>
              <span className="stat-label">Best Streak</span>
            </div>
            <div className="stat-card-small">
              <span className="stat-num">{Math.round((user?.totalCaloriesBurned || 0) / 1000)}k</span>
              <span className="stat-label">Calories</span>
            </div>
          </div>

          <h4 className="badges-title">Badges Earned</h4>
          <div className="badges-grid">
            {allBadges.map((badge, index) => (
              <div 
                key={index} 
                className={`badge-item ${badge.earned ? 'earned' : 'locked'}`}
              >
                <span className="badge-icon">{badge.earned ? badge.icon : '🔒'}</span>
                <div className="badge-info">
                  <h4>{badge.name}</h4>
                  <p>{badge.description}</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Profile;
